import random
from torch.utils.data import ConcatDataset, DataLoader, WeightedRandomSampler

def multitask_sampler(
    datasets: dict[str, list],
    temperature: float = 2.0,
) -> WeightedRandomSampler:
    """Temperature-scaled multi-task sampler."""
    sizes = {name: len(ds) for name, ds in datasets.items()}
    total = sum(s ** (1 / temperature) for s in sizes.values())
    weights_per_task = {
        name: (size ** (1 / temperature)) / total
        for name, size in sizes.items()
    }
    # assign per-example weight (all examples in same task get same weight)
    sample_weights = []
    for name, ds in datasets.items():
        w = weights_per_task[name] / len(ds)  # normalise to per-example
        sample_weights.extend([w] * len(ds))

    all_data = ConcatDataset(list(datasets.values()))
    return WeightedRandomSampler(sample_weights, num_samples=len(all_data), replacement=True)

